print("Logical Operators: ")
print("Operator Logical AND : ")
print("10 == 10 and 10 >= 9 is ",10 == 10 and 10 >= 9)
print("10 == 10 and 10 <= 9 is ",10 == 10 and 10 <= 9)
print("5 and 20 is ",5 and 20)
print("4 and 0 is ",4 and 0)
print("0 and 0 is ",0 and 0)
print("Operator Logical OR : ")
print("10 == 10 or 10 >= 9 is ",10 == 10 or 10 >= 9)
print("10 == 10 or 10 <= 9 is ",10 == 10 or 10 <= 9)
print("5 or 20 is ",5 or 20)
print("4 or 0 is ",4 or 0)
print("0 or 0 is ",0 or 0)
print("Operator Logical Not : ")
print("not(10 == 10 or 10 >= 9) is ",not(10 == 10 or 10 >= 9))
print("not(10 == 10 and 10 <= 9) is ",not(10 == 10 and 10 <= 9))

